from dataclasses import dataclass
from typing import List


SPRINT_WEEKS = 2
SPRINTS_PER_QUARTER = 6
TEAM_SIZE = 4


@dataclass
class QuarterlyRoadmap:
    quarter: str
    capacity_sprint_weeks: int   # team_size * sprints_per_quarter
    committed: List[ReliabilityItem]
    stretch: List[ReliabilityItem]

    @property
    def committed_effort(self) -> int:
        return sum(i.effort.value for i in self.committed)

    @property
    def stretch_effort(self) -> int:
        return sum(i.effort.value for i in self.stretch)

    def utilization_pct(self) -> float:
        return (self.committed_effort / self.capacity_sprint_weeks) * 100

    def print_plan(self) -> None:
        print(f"\n=== {self.quarter} Reliability Roadmap ===")
        print(f"Capacity: {self.capacity_sprint_weeks} sprint-weeks | "
              f"Committed: {self.committed_effort} ({self.utilization_pct():.0f}%)")
        print("\nCOMMITTED:")
        for item in self.committed:
            print(f"  [{item.id}] {item.title} — {item.effort.name} ({item.owner})")
        if self.stretch:
            print("\nSTRETCH (if capacity allows):")
            for item in self.stretch:
                print(f"  [{item.id}] {item.title} — {item.effort.name} ({item.owner})")


def build_quarterly_roadmap(
    ranked: List[ReliabilityItem],
    quarter: str,
    capacity_pct: float = 0.70,   # reserve 30% for incidents and toil
) -> QuarterlyRoadmap:
    total_capacity = TEAM_SIZE * SPRINTS_PER_QUARTER  # sprint-weeks
    usable = int(total_capacity * capacity_pct)
    stretch_cap = int(total_capacity * 0.15)

    committed, stretch = [], []
    used = 0
    for item in ranked:
        if used + item.effort.value <= usable:
            committed.append(item)
            used += item.effort.value
        elif used + item.effort.value <= usable + stretch_cap:
            stretch.append(item)
        else:
            break   # remaining items go to next quarter

    return QuarterlyRoadmap(quarter, usable, committed, stretch)

from dataclasses import dataclass, field
from typing import List, Set


@dataclass
class RoadmapItem:
    id: str
    title: str
    effort: int                          # sprint-weeks
    depends_on: List[str] = field(default_factory=list)   # list of item ids
    priority_score: float = 0.0


def topological_sort(items: List[RoadmapItem]) -> List[RoadmapItem]:
    """
    Sort roadmap items so that all dependencies of an item appear
    before the item itself. Raises ValueError on circular dependencies.
    """
    by_id = {i.id: i for i in items}
    order, visited, in_stack = [], set(), set()

    def visit(item_id: str) -> None:
        if item_id in in_stack:
            raise ValueError(f"Circular dependency detected at {item_id}")
        if item_id in visited:
            return
        in_stack.add(item_id)
        for dep in by_id[item_id].depends_on:
            if dep in by_id:
                visit(dep)
        in_stack.remove(item_id)
        visited.add(item_id)
        order.append(by_id[item_id])

    for item in items:
        visit(item.id)

    # Within topological order, prefer higher-priority-score items
    # while respecting dependency constraints
    return order

from dataclasses import dataclass
from enum import Enum
from typing import List, Optional


class ItemOutcome(Enum):
    SHIPPED = "shipped"
    SLIPPED = "slipped"
    CANCELLED = "cancelled"
    IN_PROGRESS = "in_progress"


@dataclass
class RoadmapReview:
    quarter: str
    items: List[dict]   # [{"id": ..., "outcome": ItemOutcome, "slip_reason": ...}]

    def shipped_count(self) -> int:
        return sum(1 for i in self.items if i["outcome"] == ItemOutcome.SHIPPED)

    def slip_rate(self) -> float:
        slipped = sum(1 for i in self.items if i["outcome"] == ItemOutcome.SLIPPED)
        total = len(self.items)
        return slipped / total if total > 0 else 0.0

    def slip_summary(self) -> List[str]:
        return [
            f"{i['id']}: {i.get('slip_reason', 'no reason given')}"
            for i in self.items
            if i["outcome"] == ItemOutcome.SLIPPED
        ]

    def health_signal(self) -> str:
        rate = self.slip_rate()
        if rate < 0.15:
            return "HEALTHY — slip rate below 15%"
        elif rate < 0.30:
            return "WARNING — slip rate elevated; review planning accuracy"
        else:
            return "CRITICAL — slip rate above 30%; capacity model or scope is wrong"
